/**
	 * Hooked on before `process_legacy_payment` and logs any data recording during
	 * the checkout process on client-side.
	 *
	 * If the checkout recorded an error, skip validating the checkout fields by setting the
	 * 'error' status on the PaymentResult.
	 *
	 * @since 2.5
	 * @param PaymentContext $context Holds context for the payment.
	 * @param PaymentResult  $result  Result of the payment.
	 */
function log_js_data( PaymentContext $context, PaymentResult &$result ) {
		if ( 'square_credit_card' === $context->payment_method ) {
			if ( ! empty( $context->payment_data['log-data'] ) ) {
				$log_data = json_decode( $context->payment_data['log-data'], true );

				if ( ! empty( $log_data ) ) {
					foreach ( $log_data as $data ) {
						$message = sprintf( "[Checkout Block] Square.js Response:\n %s", print_r( wc_clean( $data ), true ) ); //phpcs:ignore WordPress.PHP.DevelopmentFunctions.error_log_print_r
						$this->plugin->log( $message, $this->get_gateway()->get_id() );
					}
				}
			}

			if ( ! empty( $context->payment_data['checkout-notices'] ) ) {
				$payment_details                    = $result->payment_details;
				$payment_details['checkoutNotices'] = $context->payment_data['checkout-notices'];

				$result->set_payment_details( $payment_details );
				$result->set_status( 'error' );
			}
		}
	}

/**
	 * Reset API credentials if merchant clicked the reset credential link.
	 *
	 * When API credentials empty, the connect button will be displayed again,
	 * allowing merchant to reconnect with other account.
	 *
	 * When WooCommerce Branding is active, this handler may not be invoked as
	 * screen ID may evaluates to something else.
	 *
	 * @since 1.2.0
	 */
function maybe_reset_api_credentials() {
		if ( empty( $_GET['reset_ppec_api_credentials'] ) ) {
			return;
		}

		if ( empty( $_GET['reset_nonce'] ) || ! wp_verify_nonce( $_GET['reset_nonce'], 'reset_ppec_api_credentials' ) ) { // phpcs:ignore WordPress.Security.ValidatedSanitizedInput.InputNotSanitized,WordPress.Security.ValidatedSanitizedInput.MissingUnslash
			return;
		}

		$settings = wc_gateway_ppec()->settings;
		$env      = $settings->_environment;
		if ( ! empty( $_GET['environment'] ) ) {
			$env = $_GET['environment']; // phpcs:ignore WordPress.Security.ValidatedSanitizedInput.InputNotSanitized,WordPress.Security.ValidatedSanitizedInput.MissingUnslash
		}
		$prefix = 'sandbox' === $env ? 'sandbox_' : '';

		foreach ( array( 'api_username', 'api_password', 'api_signature', 'api_certificate' ) as $key ) {
			$key              = $prefix . $key;
			$settings->{$key} = '';
		}

		// Save environment too as when it switches to another env and merchant
		// click the reset they'd expect to save the environment too.
		$settings->environment = 'sandbox' === $env ? 'sandbox' : 'live';

		$settings->save();

		wp_safe_redirect( wc_gateway_ppec()->get_admin_setting_link() );
	}

function actions(): void
    {
        RequestActions::request($this->action_hook, function ($action) {

            $response = false;

            switch ($action) {

                case 'reset_options':
                    $response = wps('wpopt')->settings->reset();
                    Rewriter::reload();
                    break;

                case 'restore_options':
                    $response = wps('wpopt')->moduleHandler->upgrade();
                    break;

                case 'export_options':

                    require_once WPS_ADDON_PATH . 'Exporter.class.php';

                    $exporter = new Exporter();

                    $exporter->set_raw(wps('wpopt')->settings->export());
                    $exporter->format('text');
                    $exporter->download('wpopt-export.conf');

                    unset($exporter);

                    break;

                case 'import_options':
                    $response = wps('wpopt')->settings->import($_REQUEST['conf_data']);
                    $response &= wps('wpopt')->moduleHandler->upgrade();
                    break;
            }

            if ($response) {
                $this->add_notices('success', __('Action was correctly executed', $this->context));
            }
            else {
                $this->add_notices('warning', __('Action execution failed', $this->context));
            }
        });
    }

