/**
	 * Get sources for 404 log items.
	 *
	 * @return array
	 */
function get_sources_for_log() {
		$logs = isset( $_REQUEST['log'] ) ? array_map( 'absint', $_REQUEST['log'] ) : [];
		$logs = Monitor_DB::get_logs(
			[
				'ids'     => $logs,
				'orderby' => '',
				'limit'   => 1000,
			]
		);

		$sources = [];
		foreach ( $logs['logs'] as $log ) {
			if ( empty( $log['uri'] ) ) {
				continue;
			}
			$sources[] = [
				'pattern'    => $log['uri'],
				'comparison' => 'exact',
			];
		}

		return $sources;
	}

